import AppKit
import CoreGraphics

/// Production implementation of `KeyEventSynthesizer` using CGEvent APIs.
@MainActor
final class CGKeyEventSynthesizer: KeyEventSynthesizer {

    func simulatePaste() -> Bool {
        let source = CGEventSource(stateID: .hidSystemState)

        guard let keyDown = CGEvent(keyboardEventSource: source, virtualKey: 0x09, keyDown: true),
              let keyUp = CGEvent(keyboardEventSource: source, virtualKey: 0x09, keyDown: false) else {
            Log.output.error("Failed to create CGEvent for paste")
            return false
        }

        // 0x09 = 'v' key, add Command flag
        keyDown.flags = .maskCommand
        keyUp.flags = .maskCommand

        keyDown.post(tap: .cghidEventTap)
        keyUp.post(tap: .cghidEventTap)

        return true
    }

    func simulateBackspaces(count: Int) {
        // Use a private event source so our synthetic events don't pick up
        // any modifier keys the user may still be holding (Fn, Option, etc.)
        let source = CGEventSource(stateID: .privateState)
        // 0x33 = Delete (backspace) key
        for _ in 0..<count {
            guard let keyDown = CGEvent(keyboardEventSource: source, virtualKey: 0x33, keyDown: true),
                  let keyUp = CGEvent(keyboardEventSource: source, virtualKey: 0x33, keyDown: false) else {
                Log.output.error("Failed to create CGEvent for backspace")
                return
            }
            // Explicitly clear all modifier flags so no app misinterprets the backspace
            keyDown.flags = []
            keyUp.flags = []
            keyDown.post(tap: .cghidEventTap)
            keyUp.post(tap: .cghidEventTap)
        }
    }

    func simulateCtrlU() {
        let source = CGEventSource(stateID: .privateState)
        // 0x20 = 'u' key
        guard let keyDown = CGEvent(keyboardEventSource: source, virtualKey: 0x20, keyDown: true),
              let
