import AppKit

/// Centralized activation-policy manager for all app windows.
///
/// Tracks managed windows and coordinates `.regular` ↔ `.accessory` transitions.
/// Hard Rule #13: always wait ~100ms after `setActivationPolicy(.regular)` before activating.
@MainActor
final class WindowPresenter {
    private struct ManagedWindow {
        let observer: NSObjectProtocol
        let onClose: @MainActor () -> Void
    }

    private var managedWindows: [ObjectIdentifier: ManagedWindow] = [:]

    /// Register a window as managed, switching to `.regular` if this is the first.
    func present(_ window: NSWindow, onClose: @escaping @MainActor () -> Void = {}) {
        let id = ObjectIdentifier(window)
        let wasEmpty = managedWindows.isEmpty

        if managedWindows[id] == nil {
            let observer = NotificationCenter.default.addObserver(
                forName: NSWindow.willCloseNotification,
                object: window,
                queue: nil
            ) { [weak self, weak window] _ in
                guard let self, let window else { return }
                MainActor.assumeIsolated {
                    self.cleanup(window, invokeOnClose: true)
                }
            }

            managedWindows[id] = ManagedWindow(observer: observer, onClose: onClose)
        }

        if wasEmpty {
            NSApp.setActivationPolicy(.regular)
            // Hard Rule #13: 100ms sleep after policy change before activate
            // Hard Rule #12: Use Task.sleep, not DispatchQueue.main.asyncAfter
            // (GCD timers inside @MainActor context deadlock in .accessory mode)
            Task { [weak window] in
                try await Task.sleep(for: .milliseconds(100))
                NSApp.activate(ignoringOtherApps: true)
                // Extra 50ms for activation to propagate to the window server
                // before presenting the window. Without this, SwiftUI's
                // NSHosting
