import Foundation
import Observation
import os.lock
import TunedVoiceKit

/// Runs the bundled `run_mining.py` local mining pipeline as a subprocess and
/// streams its output into the mining log category.
///
/// Cloud scan path (tv_mine.py) has been removed — this runner now exclusively
/// handles the local on-device Qwen3.5-9B batch via `run_mining.py`.
///
/// ## Session UUID + cancellable-subprocess pattern
///
/// Every call to `runLocalBatch()` captures a fresh `UUID` (`myToken`). That
/// token is assigned to `currentToken` BEFORE the worker `Task` is spawned, so
/// any subsequent supersession or cancellation can compare against it. Every
/// single write to published state (`isRunning`, `isCancelling`,
/// `lastScanStartedAt`, `lastScanEndedAt`, `lastErrorMessage`, `lastRunStatus`)
/// inside the worker task is guarded by `guard currentToken == myToken else { return }` — this
/// guarantees that a superseded "zombie" run can never clobber the state of a
/// newer run.
///
/// The subprocess itself is launched inside `withTaskCancellationHandler`. The
/// `onCancel` closure runs on an arbitrary executor, so the `Process` reference
/// is held inside an `OSAllocatedUnfairLock`.
///
/// `cancelScan()` is deliberately **synchronous** and does NOT `await` anything.
/// It fires `currentTask?.cancel()` and returns immediately.
@MainActor
@Observable
final class MiningPipelineRunner {

    // MARK: - Published state (read by SwiftUI views)

    /// True while a scan is actively running (subprocess spawned, not yet exited).
    private(set) var isRunning: Bool = false

    /// True briefly while a cancel has been requested but the subprocess has not
    /// yet exited. Views can use this to show a "Cancelling…" affordance.
    private(set) var isCancelling: Bool = false

    /// Timestamp of the most recent `runLocalBatch()` invocation.
    private(set) var lastScanStartedAt: Date?

