import FluidAudio
import Foundation
import TunedVoiceKit
import UserNotifications

/// Brute-force streaming transcription using Parakeet.
///
/// Instead of chunking audio, this service accumulates the full audio buffer
/// and re-runs Parakeet on it periodically. Each pass replaces the previous
/// partial result. Parakeet is fast enough (~20ms per second of audio) that
/// this approach produces near-real-time updates without chunking artifacts.
///
/// Tracks per-word instability across passes: words that change between
/// re-transcriptions get higher uncertainty scores. On the final pass,
/// combines streaming instability with token confidence to produce
/// `WordUncertainty` data for downstream LLM consumption.
///
/// CTC boosting is disabled during streaming passes for speed and enabled
/// only on the final pass for maximum accuracy.
actor ParakeetStreamingService: StreamingTranscriptionService {
    private let engine: any ParakeetEngineProtocol
    private var accumulatedSamples: [Float] = []
    private var continuation: AsyncThrowingStream<StreamingTranscriptUpdate, Error>.Continuation?
    private var periodicTask: Task<Void, Never>?
    private var _isStreaming = false
    private var isTranscribing = false
    private var lastTranscribedSampleCount = 0
