        static let `default` = RetentionPolicy(
            maxAgeDays: TunedVoiceConstants.defaultRetentionDays,
            maxTotalBytes: Int64(TunedVoiceConstants.defaultRetentionMaxMB) * 1024 * 1024
        )
    }

    nonisolated private static let recordingFilenameDateFormatter: DateFormatter = {
        let formatter = DateFormatter()
        formatter.dateFormat = "yyyyMMdd-HHmmss"
        formatter.locale = Locale(identifier: "en_US_POSIX")
        return formatter
    }()

    nonisolated private let recordingsDirectoryOverride: URL?
    private let currentDate: @Sendable () -> Date

    /// Cached security-scoped bookmark URL. Resolved once, scope started once.
    /// Uses `nonisolated(unsafe)` because `recordingsDirectoryURL()` is `nonisolated`
    /// and called from multiple threads. The bookmark URL only changes when the user
    /// picks a new directory in Settings (extremely rare), so the race window is
    /// negligible -- worst case is a redundant `startAccessingSecurityScopedResource`
    /// call which harmlessly increments the kernel refcount.
    private nonisolated(unsafe) var cachedBookmarkURL: URL?
    private nonisolated(unsafe) var bookmarkScopeActive: Bool = false

    init(
        recordingsDirectoryURL: URL? = nil,
        currentDate: @escaping @Sendable () -> Date = Date.init
    ) {
        self.recordingsDirectoryOverride = recordingsDirectoryURL
        self.currentDate = currentDate
    }

